def pair_score(sims, weights):
    num = sum(sims[k] * weights[k] for k in weights)
    den = sum(weights.values())
    return num / den if den else 0.0

def decide(score, t_high=0.9, t_low=0.5):
    if score >= t_high:
        return "auto_match"
    if score <= t_low:
        return "non_match"
    return "review"

sims = {"name": 0.95, "email": 1.0, "phone": 0.0}
weights = {"name": 0.5, "email": 0.4, "phone": 0.1}
s = pair_score(sims, weights)
print("score", round(s, 3))
print("decision", decide(s))
print("explain", sims)

class UnionFind:
    def __init__(self):
        self.p = {}
    def find(self, x):
        self.p.setdefault(x, x)
        if self.p[x] != x:
            self.p[x] = self.find(self.p[x])
        return self.p[x]
    def union(self, a, b):
        ra, rb = self.find(a), self.find(b)
        if ra != rb:
            self.p[rb] = ra

